      CREATE OR REPLACE FUNCTION notify_hl7_diagnostic_order_test_created()
RETURNS TRIGGER AS $function$
      BEGIN
      INSERT INTO ${hl7.integrationSchema}.hl7_event (
        id,
        event_type,
        object_key,
        event_datetime
      )
      VALUES (
               gen_random_uuid()::varchar,
               '${hl7.events.orderCreated}',
               NEW.id::varchar,
               NOW()
             );

      RETURN NEW;
      END;
      $function$ LANGUAGE plpgsql;


DROP TRIGGER IF EXISTS trg_hl7_diagnostic_order_test_created ON diagnostic_order_tests;

CREATE TRIGGER trg_hl7_diagnostic_order_test_created
  AFTER INSERT ON diagnostic_order_tests
  FOR EACH ROW
  EXECUTE FUNCTION notify_hl7_diagnostic_order_test_created();
